"use client";

import { useTranslations, useLocale } from "next-intl";
import { Link, useRouter } from "@/i18n/navigation";
import { Badge } from "@/shared/components/ui/Badge";
import { Button } from "@/shared/components/ui/Button";
import { Card } from "@/shared/components/ui/Card";
import type { Quote } from "../types";
import {
  formatCurrency,
  calculateLineItemTotal,
  calculateSubtotal,
  calculateTotal,
} from "../types";
import { acceptQuoteAction } from "../actions";
import { Download, CheckCircle2 } from "lucide-react";
import { useState } from "react";

const STATUS_VARIANTS = {
  draft: "default",
  sent: "cyan",
  accepted: "green",
  rejected: "red",
} as const;

export function QuoteViewer({ quote }: { quote: Quote }) {
  const t = useTranslations("Quote");
  const locale = useLocale();
  const router = useRouter();
  const [accepting, setAccepting] = useState(false);

  const subtotal = calculateSubtotal(quote.lineItems);
  const discountAmount = subtotal * (quote.discount / 100);
  const total = calculateTotal(quote.lineItems, quote.discount);

  async function handleAccept() {
    setAccepting(true);
    await acceptQuoteAction(quote.id);
    router.refresh();
  }

  const dateFormatLocale = quote.locale === "es" ? "es-MX" : "en-US";

  return (
    <div className="min-h-screen bg-grid">
      {/* Header */}
      <header className="border-b border-pragma-border bg-pragma-bg/80 backdrop-blur-md">
        <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8 py-4 flex items-center justify-between">
          <span className="font-display text-xl font-bold text-pragma-accent">
            PRAGMA
          </span>
          <div className="flex items-center gap-1 text-xs font-medium">
            <Link
              href={`/quote/${quote.id}`}
              locale="en"
              className={`px-2 py-1 rounded transition-colors ${locale === "en" ? "text-pragma-accent" : "text-pragma-muted hover:text-pragma-text"}`}
            >
              EN
            </Link>
            <span className="text-pragma-border">|</span>
            <Link
              href={`/quote/${quote.id}`}
              locale="es"
              className={`px-2 py-1 rounded transition-colors ${locale === "es" ? "text-pragma-accent" : "text-pragma-muted hover:text-pragma-text"}`}
            >
              ES
            </Link>
          </div>
        </div>
      </header>

      <main className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8 py-8 sm:py-12 space-y-6">
        {/* Status & Title */}
        <div>
          <Badge variant={STATUS_VARIANTS[quote.status]} className="mb-4">
            {t(quote.status)}
          </Badge>

          <h1 className="font-display text-2xl sm:text-3xl font-bold">
            {quote.title}
          </h1>

          <div className="flex flex-wrap gap-3 mt-2 text-sm text-pragma-muted">
            <span>
              {t("quoteNumber")} #{quote.id}
            </span>
            <span>&middot;</span>
            <span>
              {t("date")}:{" "}
              {new Date(quote.createdAt).toLocaleDateString(dateFormatLocale)}
            </span>
            {quote.validUntil && (
              <>
                <span>&middot;</span>
                <span>
                  {t("validUntil")}: {quote.validUntil}
                </span>
              </>
            )}
          </div>

          {quote.description && (
            <p className="mt-4 text-pragma-muted">{quote.description}</p>
          )}
        </div>

        {/* Client Details */}
        <Card>
          <h3 className="text-xs font-semibold text-pragma-muted uppercase tracking-wider mb-3">
            {t("preparedFor")}
          </h3>
          <p className="font-semibold">{quote.clientName}</p>
          {quote.clientCompany && (
            <p className="text-sm text-pragma-muted">{quote.clientCompany}</p>
          )}
          <p className="text-sm text-pragma-muted">{quote.clientEmail}</p>
        </Card>

        {/* Line Items */}
        <Card className="overflow-hidden">
          {/* Desktop table */}
          <div className="hidden sm:block">
            <table className="w-full">
              <thead>
                <tr className="border-b border-pragma-border">
                  <th className="pb-3 text-left text-xs font-medium text-pragma-muted uppercase tracking-wider">
                    {t("description")}
                  </th>
                  <th className="pb-3 text-right text-xs font-medium text-pragma-muted uppercase tracking-wider">
                    {t("qty")}
                  </th>
                  <th className="pb-3 text-right text-xs font-medium text-pragma-muted uppercase tracking-wider">
                    {t("unitPrice")}
                  </th>
                  <th className="pb-3 text-right text-xs font-medium text-pragma-muted uppercase tracking-wider">
                    {t("total")}
                  </th>
                </tr>
              </thead>
              <tbody className="divide-y divide-pragma-border/30">
                {quote.lineItems.map((item) => (
                  <tr key={item.id}>
                    <td className="py-3 text-sm">{item.description}</td>
                    <td className="py-3 text-sm text-right text-pragma-muted">
                      {item.quantity}
                    </td>
                    <td className="py-3 text-sm text-right text-pragma-muted">
                      {formatCurrency(item.unitPrice, quote.currency, quote.locale)}
                    </td>
                    <td className="py-3 text-sm text-right">
                      {formatCurrency(
                        calculateLineItemTotal(item),
                        quote.currency,
                        quote.locale
                      )}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          {/* Mobile cards */}
          <div className="sm:hidden space-y-4">
            {quote.lineItems.map((item) => (
              <div
                key={item.id}
                className="bg-pragma-bg/50 rounded-lg p-4"
              >
                <p className="font-medium text-sm">{item.description}</p>
                <div className="flex justify-between mt-2 text-sm text-pragma-muted">
                  <span>
                    {item.quantity} x{" "}
                    {formatCurrency(item.unitPrice, quote.currency, quote.locale)}
                  </span>
                  <span className="text-pragma-text">
                    {formatCurrency(
                      calculateLineItemTotal(item),
                      quote.currency,
                      quote.locale
                    )}
                  </span>
                </div>
              </div>
            ))}
          </div>

          {/* Totals */}
          <div className="border-t border-pragma-border mt-4 pt-4">
            <div className="flex flex-col items-end gap-1 text-sm">
              <div className="flex gap-8">
                <span className="text-pragma-muted">{t("subtotal")}:</span>
                <span>
                  {formatCurrency(subtotal, quote.currency, quote.locale)}
                </span>
              </div>
              {quote.discount > 0 && (
                <div className="flex gap-8">
                  <span className="text-pragma-muted">
                    {t("discount")} ({quote.discount}%):
                  </span>
                  <span className="text-red-400">
                    -{formatCurrency(discountAmount, quote.currency, quote.locale)}
                  </span>
                </div>
              )}
              <div className="flex gap-8 text-xl font-bold mt-2 px-4 py-3 rounded-lg border border-pragma-accent/30 shadow-[0_0_15px_rgba(0,240,255,0.12)]">
                <span>{t("total")}:</span>
                <span className="text-pragma-accent">
                  {formatCurrency(total, quote.currency, quote.locale)}
                </span>
              </div>
            </div>
          </div>
        </Card>

        {/* Notes */}
        {quote.notes && (
          <Card>
            <h3 className="text-xs font-semibold text-pragma-muted uppercase tracking-wider mb-3">
              {t("notes")}
            </h3>
            <p className="text-sm text-pragma-muted italic whitespace-pre-wrap">
              {quote.notes}
            </p>
          </Card>
        )}

        {/* Actions */}
        <div className="flex flex-col sm:flex-row gap-3 pt-4">
          <a href={`/api/quote/${quote.id}/pdf`} download>
            <Button variant="secondary" size="lg">
              <Download size={18} />
              {t("downloadPdf")}
            </Button>
          </a>
          {quote.status === "sent" && (
            <Button
              variant="success"
              size="lg"
              onClick={handleAccept}
              disabled={accepting}
            >
              <CheckCircle2 size={18} />
              {accepting ? t("accepted") + "..." : t("acceptQuote")}
            </Button>
          )}
          {quote.status === "accepted" && (
            <Badge variant="green" className="px-4 py-2 text-sm">
              <CheckCircle2 size={16} className="mr-1" />
              {t("accepted")}
            </Badge>
          )}
        </div>
      </main>

      {/* Footer */}
      <footer className="border-t border-pragma-border mt-12">
        <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8 py-6 text-center">
          <p className="text-xs text-pragma-muted">{t("poweredBy")}</p>
        </div>
      </footer>
    </div>
  );
}

import {
  Document,
  Page,
  Text,
  View,
  StyleSheet,
} from "@react-pdf/renderer";
import type { Quote } from "../types";
import {
  formatCurrency,
  calculateLineItemTotal,
  calculateSubtotal,
  calculateTotal,
} from "../types";

const colors = {
  bg: "#0a0a0f",
  surface: "#12121a",
  border: "#1e1e2e",
  accent: "#00f0ff",
  text: "#e4e4e7",
  muted: "#71717a",
};

const styles = StyleSheet.create({
  page: {
    padding: 40,
    backgroundColor: "#ffffff",
    color: "#1a1a2e",
    fontFamily: "Helvetica",
    fontSize: 10,
  },
  header: {
    flexDirection: "row",
    justifyContent: "space-between",
    marginBottom: 30,
    paddingBottom: 15,
    borderBottomWidth: 2,
    borderBottomColor: colors.accent,
  },
  logo: {
    fontSize: 24,
    fontFamily: "Helvetica-Bold",
    color: colors.accent,
  },
  headerRight: {
    textAlign: "right",
  },
  headerLabel: {
    fontSize: 8,
    color: colors.muted,
    marginBottom: 2,
  },
  headerValue: {
    fontSize: 10,
    marginBottom: 4,
  },
  title: {
    fontSize: 18,
    fontFamily: "Helvetica-Bold",
    marginBottom: 6,
    color: "#1a1a2e",
  },
  description: {
    fontSize: 10,
    color: colors.muted,
    marginBottom: 20,
  },
  clientBox: {
    backgroundColor: "#f5f5f5",
    borderRadius: 4,
    padding: 12,
    marginBottom: 20,
  },
  clientLabel: {
    fontSize: 8,
    color: colors.muted,
    marginBottom: 6,
    textTransform: "uppercase",
    letterSpacing: 1,
  },
  clientName: {
    fontSize: 12,
    fontFamily: "Helvetica-Bold",
    marginBottom: 2,
  },
  clientDetail: {
    fontSize: 9,
    color: colors.muted,
  },
  tableHeader: {
    flexDirection: "row",
    borderBottomWidth: 1,
    borderBottomColor: "#e0e0e0",
    paddingBottom: 6,
    marginBottom: 4,
  },
  tableHeaderText: {
    fontSize: 8,
    color: colors.muted,
    textTransform: "uppercase",
    letterSpacing: 0.5,
  },
  tableRow: {
    flexDirection: "row",
    paddingVertical: 6,
    borderBottomWidth: 0.5,
    borderBottomColor: "#f0f0f0",
  },
  colDesc: { flex: 5 },
  colQty: { flex: 1, textAlign: "right" },
  colPrice: { flex: 2, textAlign: "right" },
  colTotal: { flex: 2, textAlign: "right" },
  totalsSection: {
    marginTop: 12,
    paddingTop: 8,
    alignItems: "flex-end",
  },
  totalRow: {
    flexDirection: "row",
    justifyContent: "flex-end",
    marginBottom: 4,
  },
  totalLabel: {
    width: 100,
    textAlign: "right",
    color: colors.muted,
    fontSize: 10,
  },
  totalValue: {
    width: 100,
    textAlign: "right",
    fontSize: 10,
  },
  grandTotal: {
    flexDirection: "row",
    justifyContent: "flex-end",
    borderTopWidth: 2,
    borderTopColor: colors.accent,
    paddingTop: 6,
    marginTop: 4,
  },
  grandTotalLabel: {
    width: 100,
    textAlign: "right",
    fontSize: 14,
    fontFamily: "Helvetica-Bold",
  },
  grandTotalValue: {
    width: 100,
    textAlign: "right",
    fontSize: 14,
    fontFamily: "Helvetica-Bold",
    color: "#0066cc",
  },
  notesBox: {
    marginTop: 24,
    backgroundColor: "#fafafa",
    borderRadius: 4,
    padding: 12,
  },
  notesLabel: {
    fontSize: 8,
    color: colors.muted,
    textTransform: "uppercase",
    letterSpacing: 1,
    marginBottom: 6,
  },
  notesText: {
    fontSize: 9,
    color: "#555",
    lineHeight: 1.5,
  },
  footer: {
    position: "absolute",
    bottom: 30,
    left: 40,
    right: 40,
    borderTopWidth: 1,
    borderTopColor: "#e0e0e0",
    paddingTop: 10,
    flexDirection: "row",
    justifyContent: "space-between",
  },
  footerText: {
    fontSize: 8,
    color: colors.muted,
  },
});

export function QuotePdfDocument({ quote }: { quote: Quote }) {
  const subtotal = calculateSubtotal(quote.lineItems);
  const discountAmount = subtotal * (quote.discount / 100);
  const total = calculateTotal(quote.lineItems, quote.discount);

  return (
    <Document>
      <Page size="A4" style={styles.page}>
        {/* Header */}
        <View style={styles.header}>
          <Text style={styles.logo}>PRAGMA</Text>
          <View style={styles.headerRight}>
            <Text style={styles.headerLabel}>QUOTE</Text>
            <Text style={styles.headerValue}>#{quote.id}</Text>
            <Text style={styles.headerLabel}>DATE</Text>
            <Text style={styles.headerValue}>
              {new Date(quote.createdAt).toLocaleDateString()}
            </Text>
            {quote.validUntil && (
              <>
                <Text style={styles.headerLabel}>VALID UNTIL</Text>
                <Text style={styles.headerValue}>{quote.validUntil}</Text>
              </>
            )}
          </View>
        </View>

        {/* Title */}
        <Text style={styles.title}>{quote.title}</Text>
        {quote.description && (
          <Text style={styles.description}>{quote.description}</Text>
        )}

        {/* Client */}
        <View style={styles.clientBox}>
          <Text style={styles.clientLabel}>Prepared for</Text>
          <Text style={styles.clientName}>{quote.clientName}</Text>
          {quote.clientCompany && (
            <Text style={styles.clientDetail}>{quote.clientCompany}</Text>
          )}
          <Text style={styles.clientDetail}>{quote.clientEmail}</Text>
        </View>

        {/* Table Header */}
        <View style={styles.tableHeader}>
          <Text style={[styles.tableHeaderText, styles.colDesc]}>
            Description
          </Text>
          <Text style={[styles.tableHeaderText, styles.colQty]}>Qty</Text>
          <Text style={[styles.tableHeaderText, styles.colPrice]}>
            Unit Price
          </Text>
          <Text style={[styles.tableHeaderText, styles.colTotal]}>Total</Text>
        </View>

        {/* Table Rows */}
        {quote.lineItems.map((item) => (
          <View key={item.id} style={styles.tableRow}>
            <Text style={styles.colDesc}>{item.description}</Text>
            <Text style={styles.colQty}>{item.quantity}</Text>
            <Text style={styles.colPrice}>
              {formatCurrency(item.unitPrice, quote.currency, quote.locale)}
            </Text>
            <Text style={styles.colTotal}>
              {formatCurrency(
                calculateLineItemTotal(item),
                quote.currency,
                quote.locale
              )}
            </Text>
          </View>
        ))}

        {/* Totals */}
        <View style={styles.totalsSection}>
          <View style={styles.totalRow}>
            <Text style={styles.totalLabel}>Subtotal:</Text>
            <Text style={styles.totalValue}>
              {formatCurrency(subtotal, quote.currency, quote.locale)}
            </Text>
          </View>
          {quote.discount > 0 && (
            <View style={styles.totalRow}>
              <Text style={styles.totalLabel}>
                Discount ({quote.discount}%):
              </Text>
              <Text style={[styles.totalValue, { color: "#cc0000" }]}>
                -{formatCurrency(discountAmount, quote.currency, quote.locale)}
              </Text>
            </View>
          )}
          <View style={styles.grandTotal}>
            <Text style={styles.grandTotalLabel}>Total:</Text>
            <Text style={styles.grandTotalValue}>
              {formatCurrency(total, quote.currency, quote.locale)}
            </Text>
          </View>
        </View>

        {/* Notes */}
        {quote.notes && (
          <View style={styles.notesBox}>
            <Text style={styles.notesLabel}>Notes & Terms</Text>
