  preferentialNote: z.string().optional(),
  paymentTerms: z.string().optional(),
  nextSteps: z.array(z.string()).optional(),
  scopeNote: z.string().optional(),
});

export type QuoteFormData = z.infer<typeof quoteFormSchema>;

