    ]
  },
  "hooks": {
    "PreToolUse": [
      {
        "matcher": "",
        "hooks": [
          {
            "type": "command",
            "command": "uv run ~/.claude/scripts/log-hook.py pre"
          }
        ]
      },
      {
        "matcher": "",
        "hooks": [
